#include<bits/stdc++.h>
#define ll long long
using namespace std;
struct node{
	int num,val,x;
    bool operator < (const node &a) const {
        return a.val<val;
    }
};const int MAXN=1e4+5;
int n,a[MAXN],b[MAXN],c[MAXN],m;
priority_queue<node> q;
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	scanf("%d%d",&n,&m);
	for(int i=1;i<=n;++i)scanf("%d%d%d",a+i,b+i,c+i);
	for(int i=1;i<=n;++i)q.push({i,a[i]+b[i]+c[i],1});
	for(int i=0;i<m;++i){
		printf("%d ",q.top().val);
		int e=a[q.top().num]*((q.top().x+1)*(q.top().x+1));
		int p=b[q.top().num]*(q.top().x+1),d=c[q.top().num];
		q.push({q.top().num,e+p+d,q.top().x+1});
		q.pop();
	}
	return false;
}
